     {q:"The passengers of the Komagata Maru were ___ entry into Canada.", options:["Offered citizenship without any restrictions","Immediately and fully granted","Largely denied","A response unrelated to the Komagata Maru incident"], answer:2},
     {q:"The Komagata Maru incident occurred in ___.", options:["1867","A year unrelated to the Komagata Maru incident","1950","1914"], answer:3},
     {q:"The Komagata Maru incident is often cited as an example of ___.", options:["A modern immigration policy with no historical roots","Discriminatory Canadian immigration policy in the early 20th century","A concept unrelated to the Komagata Maru incident","A completely fair and welcoming immigration process"], answer:1},
     {q:"Why does the Canadian government now formally acknowledge the Komagata Maru incident?", options:["The event has been officially declared to have never happened","The incident has no connection to Canadian immigration history","To recognize past discrimination and its lasting impact on affected communities","A reason unrelated to the Komagata Maru incident"], answer:2}
